#include <bits/stdc++.h>using namespace std; const int MAX = 1e6; vector<bool> sieve(MAX + 1, true); void precompute() {    sieve[0] = sieve[1] = false;     for (int i = 2; i * i <= MAX; i++) {        if (sieve[i]) {            for (int j = i * i; j <= MAX; j += i) {                sieve[j] = false;            }        }    }} int main() {    ios::sync_with_stdio(false);    cin.tie(nullptr);     precompute();     int n;    cin >> n;     vector<long long> a(n);        for (auto &x : a) {        cin >> x;    }     for (long long x : a) {        long long root = sqrtl(x);         if (root * root == x && root <= MAX && sieve[root]) {            cout << "YES\n";        } else {            cout << "NO\n";        }    }}